          const adultCount = (option.guest.adults || 0) + childAges.filter(age => age >= minAdultAge).length;
          const extraAdults = Math.max(0, adultCount - (room?.maxAdults ?? 0));
          const availableSlotsForChildren = Math.max(0, (room?.maxAdults ?? 0) - adultCount);
