  /**
   * Lấy surcharge calendar rows cho ngày cụ thể
   * Kết hợp rows của phòng và hotel
   *
   * @param calendar - Surcharge calendar map
   * @param hotelId - ID khách sạn
   * @param roomId - ID phòng
   * @param dateKey - Ngày (format YYYY-MM-DD)
   * @returns Danh sách surcharge rows
   */
  private getCalendarRowsForDate(
    calendar: SurchargeCalendarMap,
    hotelId: number,
    roomId: number,
    dateKey: string,
  ): SurchargeRateCalendarRow[] {
    const roomRows = calendar.byRoomDate.get(`${roomId}:${dateKey}`) ?? [];
    const hotelRows = calendar.byHotelDate.get(`${hotelId}:${dateKey}`) ?? [];
    return roomRows.concat(...hotelRows);
  }

